for p in POSTS:
    try:
        # Verifica se já existe pelo slug
        exists = sb.table("posts_blog").select("id").eq("slug", p["slug"]).execute()
        if exists.data:
            print(f"  Aviso: Post '{p['title'][:40]}...' já existe. Pulando.")
            continue
            
        sb.table("posts_blog").insert({
            "title": p["title"],
            "slug": p["slug"],
            "content": p["content"],
            "published_at": p["published_at"],
            "status": "Publicado",
            "cover_image": p.get("cover_image")
        }).execute()
        print(f"  Sucesso: {p['title'][:60]}")
    except Exception as e:
        print(f"  Erro ao inserir '{p['title'][:40]}': {e}")

